层次遍历








要进行层次遍历，需要借助一个队列，先将二叉树根结点入队，然后出队，访问该结点，若它有左子树，则将左子树根结点入队；若它有右子树，则将右子树根结点入队。然后出队，对出队结点访问，如此反复，直到队列为空。
&#x2F;*
 * 层次遍历，广度优先遍历
 *&#x2F;
void LevelOrder(BiTree T)&#123;
    LinkQueue Q;
    InitQueue(Q);
    BiTree p;
    EnQueue(Q,T);
    while (!IsEmpty(Q))&#123;
        DeQueue(Q,p);
        putchar(p-&gt;data);
        if(p-&gt;lchild!&#x3D;NULL)&#123;
            EnQueue(Q,p-&gt;lchild);
        &#125;
        if(p-&gt;rchild!&#x3D;NULL)&#123;
            EnQueue(Q,p-&gt;rchild);
        &#125;
    &#125;
&#125;

队列的链式存储的定义#define ElemType int
typedef struct LinkNode&#123;
    ElemType data;
    struct LinkNode *next;
&#125;LinkNode;
typedef struct &#123;
    LinkNode *front,*rear;
&#125;LinkQueue;

初始化队列
创建头结点，使头指针和尾指针都指向头结点
初始化为空void InitQueue(LinkQueue &amp;Q)&#123;
    Q.front&#x3D;Q.rear&#x3D;(LinkNode*)malloc(sizeof(LinkNode));&#x2F;&#x2F;创建头结点，使头指针和尾指针都指向头结点
    Q.front-&gt;next&#x3D;NULL;&#x2F;&#x2F;初始化为空
&#125;
判队空bool IsEmpty(LinkQueue Q)&#123;
    return Q.front&#x3D;&#x3D;Q.rear;
&#125;
入队操作
创建新的结点
将数据填入结点
将队尾指针的next指针指向s
将rear指向svoid EnQueue(LinkQueue &amp;Q,ElemType e)&#123;
    LinkNode *s&#x3D;(LinkNode*)malloc(sizeof(LinkNode));&#x2F;&#x2F;创建新的结点
    s-&gt;data&#x3D;e;&#x2F;&#x2F;将数据填入结点
    s-&gt;next&#x3D;NULL;
    Q.rear-&gt;next&#x3D;s;&#x2F;&#x2F;将队尾指针的next指针指向s
    Q.rear&#x3D;s;&#x2F;&#x2F;将rear指向s
&#125;
出队操作
判断队列是否为空
非空，则将p指向头结点的下一个结点
获取要出队的元素
断链
如果删除的是最后一个元素，将队列置为空
释放内存bool DeQueue(LinkQueue &amp;Q,ElemType &amp;e)&#123;
    if(IsEmpty(Q))&#123;&#x2F;&#x2F;判断队列是否为空
        return false;
    &#125;
    LinkNode *p&#x3D;Q.front-&gt;next;&#x2F;&#x2F;将p指向头结点的下一个结点
    e&#x3D;p-&gt;data;&#x2F;&#x2F;获取要出队的元素
    Q.front-&gt;next&#x3D;p-&gt;next;&#x2F;&#x2F;断链
    if(Q.rear&#x3D;&#x3D;p)&#123;&#x2F;&#x2F;删除的是最后一个元素
        Q.rear&#x3D;Q.front;&#x2F;&#x2F;队列置为空
    &#125;
    free(p);
    return true;
&#125;

循环队列的定义#define MaxSize 5
#define ElemType int
typedef struct &#123;
    ElemType data[MaxSize];
    int front,rear;
&#125;SqQueue;
初始化队列
队头和队尾指针为0void InitQueue(SqQueue &amp;Q)&#123;
    Q.front&#x3D;Q.rear&#x3D;0;
&#125;
判断队空
判断队头和队尾指针是否相等bool isEmpty(SqQueue Q)&#123;
    return Q.rear &#x3D;&#x3D; Q.front;
&#125;
入队操作
判断队满
没满，则从队尾插入数据，队尾指针加一取模bool EnQueue(SqQueue &amp;Q,ElemType e)&#123;
    if((Q.rear+1)%MaxSize&#x3D;&#x3D;Q.front)&#x2F;&#x2F;判断队满
        return false;
    Q.data[Q.rear]&#x3D;e;
    Q.rear&#x3D;(Q.rear+1)%MaxSize;&#x2F;&#x2F;队尾指针加一取模
    return true;
&#125;
出队操作
判断队空
非空，则从队头获取出队元素，队头指针加一取模bool DeQueue(SqQueue &amp;Q,ElemType &amp;e)&#123;
    if(isEmpty(Q))&#x2F;&#x2F;判断队空
        return false;
    e&#x3D;Q.data[Q.front];
    Q.front&#x3D;(Q.front+1)%MaxSize;&#x2F;&#x2F;队头指针加一取模
    return true;
&#125;

栈的定义#define MaxSize 50
#define ElemType int
typedef struct &#123;
    ElemType data[MaxSize];
    int top;
&#125;SqStack;

初始化栈
top=-1代表为空栈void InitStack(SqStack &amp;S)&#123;
    S.top&#x3D;-1;&#x2F;&#x2F;top&#x3D;-1代表为空栈
&#125;

判断栈空bool StackEmpty(SqStack &amp;S)&#123;
    return S.top &#x3D;&#x3D; -1;
&#125;

入栈操作
判断是否栈满
非空，则将栈顶指针加一再入栈bool Push(SqStack &amp;S,ElemType e)&#123;
    if(S.top&#x3D;&#x3D;MaxSize-1)&#x2F;&#x2F;判断是否栈满
    &#123;
        return false;
    &#125;
    S.data[++S.top]&#x3D;e;&#x2F;&#x2F;栈顶指针加一再入栈
    return true;
&#125;

出栈操作
判断是否为空栈
非空,则记录出栈的元素,栈顶指针减一bool Pop(SqStack &amp;S,ElemType &amp;e)&#123;
    if(S.top&#x3D;&#x3D;-1)&#x2F;&#x2F;判断是否为空栈
    &#123;
        return false;
    &#125;
    e&#x3D;S.data[S.top--];&#x2F;&#x2F;记录出栈的元素
    return true;
&#125;

读取栈顶元素
判断是否为空栈
非空,则直接读取栈顶元素bool GetTop(SqStack S,ElemType &amp;e)&#123;
    if(S.top&#x3D;&#x3D;-1)&#x2F;&#x2F;判断是否为空栈
    &#123;
        return false;
    &#125;
    e&#x3D;S.data[S.top];&#x2F;&#x2F;记录栈顶元素
    return true;
&#125;

