创建适配器类MessageAdapter，并让其继承RecyclerView.Adapter








  将泛型指定为MessageAdapter.ViewHolder，然后在MessageAdapter中定义一个ViewHolder内部类。重写RecyclerView.Adapter的onCreateViewHolder，onBindViewHolder，getItemCount三个方法，onCreateViewHolder负责承载每个子项的布局，onBindViewHolder负责将每个子项holder绑定数据，getItemCount用来返回显示的item数。
 注意： 关于inflate方法，我们主要使用这两个方法

View.inflate(Context context, @LayoutRes int resource, ViewGroup root);
LayoutInflater.from(Context context).inflate(@LayoutRes int resource, ViewGroup root, boolean attachToRoot);


如果root为null，attachToRoot将失去作用，
如果root不为null，attachToRoot设置为true，则会给加载的布局文件指定一个父布局，即为root。
如果root不为null，attachToRoot设置为false，则会将布局文件最外层的所有layout属性进行设置，当该view被添加到父view中时，这些layout属性会自动生效。
在不设置attachToRoot参数情况下，如果root不为null，attachToRoot参数默认为true。

public class MessageAdapter extends RecyclerView.Adapter&lt;MessageAdapter.ViewHolder&gt; &#123;
    List&lt;Message&gt; messageList;

    public MessageAdapter(List&lt;Message&gt; messageList) &#123;
        this.messageList &#x3D; messageList;
    &#125;

    @NonNull
    @Override
    public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) &#123;
        View itemView &#x3D; LayoutInflater.from(parent.getContext()).inflate(R.layout.message_item,null);
        ViewHolder viewHolder &#x3D; new ViewHolder(itemView);
        return viewHolder;
    &#125;

    @Override
    public void onBindViewHolder(@NonNull ViewHolder holder, int position) &#123;
        Message message &#x3D; messageList.get(position);
        holder.image.setImageResource(message.getImageId());
        holder.name.setText(message.getName());
        holder.text.setText(message.getText());
        holder.time.setText(message.getTime());
    &#125;

    @Override
    public int getItemCount() &#123;
        return messageList.size();
    &#125;

    public class ViewHolder extends RecyclerView.ViewHolder &#123;
        ImageView image;
        TextView name;
        TextView text;
        TextView time;
        public ViewHolder(@NonNull View itemView) &#123;
            super(itemView);
            image &#x3D; itemView.findViewById(R.id.image);
            name &#x3D; itemView.findViewById(R.id.name);
            text &#x3D; itemView.findViewById(R.id.text);
            time &#x3D; itemView.findViewById(R.id.time);
        &#125;
    &#125;
