public class PeopleAdapter extends ArrayAdapter&lt;People&gt; &#123;
  private int resourceId;

  public PeopleAdapter(@NonNull Context context,  int resourceId, @NonNull List&lt;People&gt; objects) &#123;
      super(context, resourceId, objects);
      this.resourceId &#x3D; resourceId;
  &#125;

  @NonNull
  @Override
  public View getView(int position, @Nullable View convertView, @NonNull ViewGroup parent) &#123;
      People people &#x3D; getItem(position);
      View view;
      ViewHolder viewHolder;

      if(convertView &#x3D;&#x3D; null)&#123;
          view &#x3D; LayoutInflater.from(getContext()).inflate(resourceId,parent,false);
          viewHolder &#x3D; new ViewHolder();
          viewHolder.peopleImage &#x3D; view.findViewById(R.id.people_image);
          viewHolder.peopleName &#x3D; view.findViewById(R.id.people_name);
          view.setTag(viewHolder);
      &#125;else&#123;
          view &#x3D; convertView;
          viewHolder &#x3D; (ViewHolder) view.getTag();
      &#125;
      viewHolder.peopleImage.setImageResource(people.getPeopleImageId());
      viewHolder.peopleName.setText(people.getPeopleName());
      return view;
  &#125;

  class ViewHolder&#123;
      ImageView peopleImage;
      TextView peopleName;
  &#125;
